import React, { useState, useEffect } from 'react';
import './WordCloud.css';

export default function WordCloud({ onSelect, questions }) {
  const [active, setActive] = useState(null);

  // Clear active state when questions change (dataset switched)
  useEffect(() => { setActive(null); }, [questions]);

  const handleClick = (q) => {
    setActive(q.text);
    onSelect(q.text);
    setTimeout(() => setActive(null), 1500);
  };

  return (
    <div className="word-cloud-section">
      <p className="word-cloud-label">Try asking Spotter…</p>
      <div className="word-cloud">
        {questions.map((q) => (
          <button
            key={q.text}
            className={`wc-chip wc-${q.size} ${active === q.text ? 'wc-active' : ''}`}
            onClick={() => handleClick(q)}
          >
            {q.text}
          </button>
        ))}
      </div>
    </div>
  );
}
